1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type Step = { op: "quote"; items: Array<Item> };
12	type Scenario = {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Array<Step>;
15	};
16	
17	const itemPremium = (item: Item): number => {
18	  const base = BASE_PREMIUM[item.type];
19	  return base + base * FIRST_INSURANCE_RATE;
20	};
21	
22	const sumItemPremiums = (items: Array<Item>): number =>
23	  items.reduce((total, item) => total + itemPremium(item), 0);
24	
25	const quotePremium = ({ items }: Step): number =>
26	  sumItemPremiums(items) + PROCESSING_FEE;
27	
28	export const runScenario = (scenario: unknown): unknown => {
29	  const { steps } = scenario as Scenario;
30	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
31	  return { results };
32	};
